16→dependencies {
17→    implementation("com.google.code.gson:gson:2.10.1")
18→
19→    testImplementation("org.junit.jupiter:junit-jupiter:5.10.2")
20→    testImplementation("org.junit.jupiter:junit-jupiter-api:5.10.2")
21→    testRuntimeOnly("org.junit.jupiter:junit-jupiter-engine:5.10.2")
22→    testImplementation(gradleTestKit())
23→    testImplementation(kotlin("test"))
24→    testImplementation("com.squareup.okhttp3:mockwebserver:4.12.0")
25→}
26→
27→tasks.test {
28→    useJUnitPlatform()
29→}
30→
31→gradlePlugin {
32→    website = "https://tuist.dev"
33→    vcsUrl = "https://github.com/tuist/tuist"
34→    plugins {
35→        create("tuist") {
36→            id = "dev.tuist"
37→            displayName = "Tuist"
38→            description = "Integrates Gradle projects with Tuist services including remote build caching and analytics"
39→            implementationClass = "dev.tuist.gradle.TuistPlugin"
40→            tags = listOf("build-cache", "remote-cache", "tuist", "analytics")
41→        }
42→    }
43→}
44→
45→publishing {
46→    publications {
47→        create<MavenPublication>("pluginMaven") {
48→            groupId = "dev.tuist"
49→            artifactId = "tuist-gradle-plugin"
50→            version = project.version.toString()
51→        }
52→    }
53→}
54→
55→java {
56→    sourceCompatibility = JavaVersion.VERSION_17
57→    targetCompatibility = JavaVersion.VERSION_17
58→}
